import{_ as e,c as i,o,ah as n}from"./chunks/framework.C-x9UAyH.js";const r="/az_ciclo_vida_app_devops.png",f=JSON.parse('{"title":"Ciclo de vida de las aplicaciones","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"azure/ciclo_vida.md","filePath":"azure/ciclo_vida.md","lastUpdated":1760649277000}'),l={name:"azure/ciclo_vida.md"};function s(t,a,c,d,p,u){return o(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="ciclo-de-vida-de-las-aplicaciones" tabindex="-1">Ciclo de vida de las aplicaciones <a class="header-anchor" href="#ciclo-de-vida-de-las-aplicaciones" aria-label="Permalink to &quot;Ciclo de vida de las aplicaciones&quot;">​</a></h1><h2 id="planificacion" tabindex="-1">Planificación <a class="header-anchor" href="#planificacion" aria-label="Permalink to &quot;Planificación&quot;">​</a></h2><p>En la fase de planificación, los equipos de DevOps conceptualizan y detallan las características de las aplicaciones, realizando un seguimiento general y detallado del progreso. Estrategias como la creación de registros de tareas pendientes, monitoreo de errores, gestión ágil con Scrum, implementación de paneles Kanban y visualización del progreso son utilizadas para una planificación ágil y transparente.</p><h2 id="desarrollo" tabindex="-1">Desarrollo <a class="header-anchor" href="#desarrollo" aria-label="Permalink to &quot;Desarrollo&quot;">​</a></h2><p>Durante la etapa de desarrollo, los equipos de DevOps abordan aspectos como la escritura, pruebas, revisión e integración del código. Buscan la innovación a un ritmo acelerado sin comprometer la calidad, estabilidad y eficiencia, empleando herramientas productivas, automatizando tareas y mejorando el código mediante iteraciones pequeñas con pruebas automáticas e integración continua.</p><h2 id="entrega" tabindex="-1">Entrega <a class="header-anchor" href="#entrega" aria-label="Permalink to &quot;Entrega&quot;">​</a></h2><p>La entrega implica el despliegue continuo y fiable de aplicaciones en entornos de producción. Se realiza la implementación y configuración de la infraestructura base, estableciendo un proceso de gestión de versiones con fases de aprobación manual. La automatización asegura control, escalabilidad y repetibilidad, permitiendo entregas sencillas y confiables.</p><h2 id="uso" tabindex="-1">Uso <a class="header-anchor" href="#uso" aria-label="Permalink to &quot;Uso&quot;">​</a></h2><p>La fase de uso se enfoca en el mantenimiento, monitoreo y abordaje de problemas en entornos de producción. Los equipos de DevOps trabajan para garantizar la fiabilidad, alta disponibilidad y cero tiempo de inactividad, fortaleciendo la seguridad y el cumplimiento normativo. La identificación proactiva de problemas, junto con telemetría exhaustiva y alertas, es esencial para tomar medidas rápidas y mantener la visibilidad completa del sistema.</p><p align="center"><img src="'+r+'" width="800" alt="ciclo vida app devops"></p>',10)])])}const h=e(l,[["render",s]]);export{f as __pageData,h as default};
